/*
 * IoT Node Architecture - Level 1-3 Implementation
 * Demonstrates single node with optional local storage and edge analytics
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <time.h>

#define MAX_STORAGE 100
#define THRESHOLD_TEMP 35.0

/* Data structures for IoT node */
typedef struct {
    int node_id;
    float temperature;
    float humidity;
    time_t timestamp;
    bool processed;
} SensorData;

typedef struct {
    SensorData readings[MAX_STORAGE];
    int count;
    int storage_enabled;
    int analytics_enabled;
} IoTNode;

/* Function prototypes */
void init_node(IoTNode *node, int id, int storage, int analytics);
SensorData read_sensor(IoTNode *node);
float process_locally(SensorData *data);
bool analyze_edge(SensorData *data, float *action_value);
void store_local(IoTNode *node, SensorData *data);
void display_reading(SensorData *data);

/* Initialize IoT node with configuration */
void init_node(IoTNode *node, int id, int storage, int analytics) {
    node->count = 0;
    node->storage_enabled = storage;
    node->analytics_enabled = analytics;
    printf("Node %d initialized - Storage: %s, Analytics: %s\n", 
           id,
           storage ? "ENABLED" : "DISABLED",
           analytics ? "ENABLED" : "DISABLED");
}

/* Simulate sensor reading - Level 1 functionality */
SensorData read_sensor(IoTNode *node) {
    SensorData data;
    data.node_id = 1;
    /* Simulate temperature reading (20-45 C) */
    data.temperature = 20.0 + (rand() % 25);
    data.humidity = 40.0 + (rand() % 40);
    data.timestamp = time(NULL);
    data.processed = false;
    return data;
}

/* Local processing - Level 1-2 functionality */
float process_locally(SensorData *data) {
    /* Simple processing: apply calibration offset */
    float processed_temp = data->temperature * 0.98 + 0.5;
    data->processed = true;
    return processed_temp;
}

/* Edge analytics - Level 3 functionality */
bool analyze_edge(SensorData *data, float *action_value) {
    /* Check if threshold exceeded */
    if (data->temperature > THRESHOLD_TEMP) {
        *action_value = 1.0;  /* Activate cooling */
        return true;  /* Alert triggered */
    }
    *action_value = 0.0;  /* Normal operation */
    return false;
}

/* Local storage - Level 2-3 functionality */
void store_local(IoTNode *node, SensorData *data) {
    if (!node->storage_enabled) {
        return;
    }

    if (node->count < MAX_STORAGE) {
        node->readings[node->count++] = *data;
        printf("  [Storage] Record saved (count: %d)\n", node->count);
    } else {
        printf("  [Storage] Storage full, oldest record overwritten\n");
        /* Simple circular buffer - overwrite oldest */
        memmove(&node->readings[0], &node->readings[1], 
                (MAX_STORAGE - 1) * sizeof(SensorData));
        node->readings[MAX_STORAGE - 1] = *data;
    }
}

/* Display sensor reading */
void display_reading(SensorData *data) {
    printf("  Temperature: %.1f C, Humidity: %.1f %%, Processed: %s\n",
           data->temperature, 
           data->humidity,
           data->processed ? "YES" : "NO");
}

/* Simulate Level 1: Single node basic operation */
void demonstrate_level1(IoTNode *node) {
    printf("\n=== LEVEL 1: Single Node (Basic) ===\n");
    SensorData data = read_sensor(node);
    display_reading(&data);

    float result = process_locally(&data);
    printf("  Processed temperature: %.1f C\n", result);
}

/* Simulate Level 2: Add local storage */
void demonstrate_level2(IoTNode *node) {
    printf("\n=== LEVEL 2: Single Node + Local Storage ===\n");

    /* Read and store multiple readings */
    for (int i = 0; i < 3; i++) {
        SensorData data = read_sensor(node);
        process_locally(&data);
        store_local(node, &data);
        display_reading(&data);
    }
    printf("  Total stored readings: %d\n", node->count);
}

/* Simulate Level 3: Add edge analytics */
void demonstrate_level3(IoTNode *node) {
    printf("\n=== LEVEL 3: Single Node + Edge Analytics ===\n");

    SensorData data = read_sensor(node);
    process_locally(&data);
    store_local(node, &data);

    float action;
    bool alert = analyze_edge(&data, &action);

    display_reading(&data);
    printf("  Alert: %s\n", alert ? "TRIGGERED" : "NORMAL");
    printf("  Action value: %.1f\n", action);

    if (alert) {
        printf("  -> Activating cooling system!\n");
    }
}

/* Main function - demonstrate all levels */
int main(void) {
    srand(time(NULL));  /* Seed random number generator */

    printf("IoT NODE ARCHITECTURE - C Implementation\n");
    printf("==========================================\n");

    IoTNode node;

    /* Level 1: Basic single node */
    init_node(&node, 1, 0, 0);  /* No storage, no analytics */
    demonstrate_level1(&node);

    /* Level 2: Add local storage */
    init_node(&node, 1, 1, 0);  /* Storage enabled, no analytics */
    demonstrate_level2(&node);

    /* Level 3: Add edge analytics */
    init_node(&node, 1, 1, 1);  /* Storage + Analytics enabled */
    demonstrate_level3(&node);

    printf("\n==========================================\n");
    printf("Demo complete!\n");

    return 0;
}

/*
 * Multi-Node IoT System - Java Implementation
 * Demonstrates Levels 4-6 and deployment templates
 */

import java.util.*;
import java.util.stream.*;

// ============== Data Classes ==============
class SensorReading {
    private final String nodeId;
    private final double value;
    private final long timestamp;
    private final String type;

    public SensorReading(String nodeId, double value, String type) {
        this.nodeId = nodeId;
        this.value = value;
        this.timestamp = System.currentTimeMillis();
        this.type = type;
    }

    public String getNodeId() { return nodeId; }
    public double getValue() { return value; }
    public long getTimestamp() { return timestamp; }
    public String getType() { return type; }

    @Override
    public String toString() {
        return String.format("SensorReading[node=%s, value=%.1f, type=%s]", 
                             nodeId, value, type);
    }
}

// ============== Core Classes ==============
interface ProcessingUnit {
    List<SensorReading> process(List<SensorReading> data);
}

class EdgeProcessor implements ProcessingUnit {
    @Override
    public List<SensorReading> process(List<SensorReading> data) {
        System.out.println("  [Edge] Processing " + data.size() + " readings locally");
        // Simple threshold filtering at edge
        return data.stream()
            .filter(r -> r.getValue() > 0)
            .collect(Collectors.toList());
    }
}

class CloudProcessor implements ProcessingUnit {
    @Override
    public List<SensorReading> process(List<SensorReading> data) {
        System.out.println("  [Cloud] Advanced analytics on " + data.size() + " readings");
        // Cloud-level analytics (aggregations, ML, etc.)
        double avg = data.stream().mapToDouble(SensorReading::getValue).average().orElse(0);
        double max = data.stream().mapToDouble(SensorReading::getValue).max().orElse(0);
        double min = data.stream().mapToDouble(SensorReading::getValue).min().orElse(0);

        System.out.printf("    Cloud Analytics: avg=%.2f, min=%.2f, max=%.2f%n", avg, min, max);
        return data;
    }
}

class FogNode implements ProcessingUnit {
    private final String fogId;

    public FogNode(String fogId) {
        this.fogId = fogId;
    }

    @Override
    public List<SensorReading> process(List<SensorReading> data) {
        System.out.println("  [Fog-" + fogId + "] Intermediate processing");
        // Fog does aggregation before cloud
        return data;  // Pass through with potential transformation
    }
}

// ============== IoT Node ==============
class IoTNode {
    private final String nodeId;
    private final String location;

    public IoTNode(String nodeId, String location) {
        this.nodeId = nodeId;
        this.location = location;
    }

    public SensorReading readSensor() {
        // Simulate sensor reading
        double value = 20 + Math.random() * 30;
        return new SensorReading(nodeId, value, location);
    }

    public String getNodeId() { return nodeId; }
}

// ============== Central Hub (Level 4) ==============
class CentralHub {
    private final List<IoTNode> nodes = new ArrayList<>();
    private final List<SensorReading> localStorage = new ArrayList<>();

    public void registerNode(IoTNode node) {
        nodes.add(node);
        System.out.println("Hub: Registered node " + node.getNodeId());
    }

    public List<SensorReading> collectFromAllNodes() {
        List<SensorReading> readings = new ArrayList<>();
        for (IoTNode node : nodes) {
            readings.add(node.readSensor());
        }
        localStorage.addAll(readings);
        return readings;
    }

    public Map<String, Double> aggregateData(List<SensorReading> data) {
        Map<String, Double> stats = new HashMap<>();
        double avg = data.stream().mapToDouble(SensorReading::getValue).average().orElse(0);
        stats.put("average", avg);
        stats.put("count", (double) data.size());
        return stats;
    }

    public int getLocalStorageSize() { return localStorage.size(); }
}

// ============== Cloud Platform (Level 5-6) ==============
class CloudPlatform {
    private final List<SensorReading> cloudStorage = new ArrayList<>();
    private final ProcessingUnit cloudProcessor = new CloudProcessor();

    public void store(List<SensorReading> data) {
        cloudStorage.addAll(data);
        System.out.println("  [Cloud] Stored " + data.size() + " readings (total: " + cloudStorage.size() + ")");
    }

    public Map<String, Double> advancedAnalytics(List<SensorReading> data) {
        cloudProcessor.process(data);
        Map<String, Double> analytics = new HashMap<>();
        analytics.put("totalProcessed", (double) cloudStorage.size());
        return analytics;
    }
}

// ============== Deployment Templates ==============
enum DeploymentTemplate {
    CLOUD_CENTRIC {
        @Override
        public void deploy() {
            System.out.println("\n=== CLOUD-CENTRIC DEPLOYMENT ===");
            CentralHub hub = new CentralHub();
            CloudPlatform cloud = new CloudPlatform();

            // Register nodes
            for (int i = 1; i <= 3; i++) {
                hub.registerNode(new IoTNode("node-" + i, "field"));
            }

            // Collect and send directly to cloud
            List<SensorReading> data = hub.collectFromAllNodes();
            data.forEach(r -> System.out.println("  Sending to cloud: " + r));
            cloud.store(data);
            cloud.advancedAnalytics(data);
        }
    },

    EDGE_CENTRIC {
        @Override
        public void deploy() {
            System.out.println("\n=== EDGE-CENTRIC DEPLOYMENT ===");
            ProcessingUnit edge = new EdgeProcessor();
            CloudPlatform cloud = new CloudPlatform();

            // Simulate edge processing first
            List<SensorReading> rawData = new ArrayList<>();
            for (int i = 1; i <= 3; i++) {
                IoTNode node = new IoTNode("edge-node-" + i, "factory");
                rawData.add(node.readSensor());
            }

            List<SensorReading> processedData = edge.process(rawData);
            System.out.println("  Edge processed " + processedData.size() + " readings");

            // Only sync important data to cloud
            cloud.store(processedData);
        }
    },

    FOG_COMPUTING {
        @Override
        public void deploy() {
            System.out.println("\n=== FOG COMPUTING DEPLOYMENT ===");
            FogNode fog = new FogNode("A");
            CloudPlatform cloud = new CloudPlatform();

            List<SensorReading> rawData = new ArrayList<>();
            for (int i = 1; i <= 4; i++) {
                IoTNode node = new IoTNode("sensor-" + i, "warehouse");
                rawData.add(node.readSensor());
            }

            // Fog processes before cloud
            fog.process(rawData);
            cloud.store(rawData);
            cloud.advancedAnalytics(rawData);
        }
    },

    HYBRID {
        @Override
        public void deploy() {
            System.out.println("\n=== HYBRID DEPLOYMENT (Level 6) ===");
            ProcessingUnit edge = new EdgeProcessor();
            FogNode fog = new FogNode("1");
            CloudPlatform cloud = new CloudPlatform();

            // Step 1: Edge processing
            List<SensorReading> edgeData = new ArrayList<>();
            for (int i = 1; i <= 3; i++) {
                IoTNode node = new IoTNode("smart-sensor-" + i, "city");
                edgeData.add(node.readSensor());
            }

            List<SensorReading> edgeProcessed = edge.process(edgeData);

            // Step 2: Fog aggregation
            fog.process(edgeProcessed);

            // Step 3: Cloud analytics
            cloud.store(edgeProcessed);
            cloud.advancedAnalytics(edgeProcessed);

            System.out.println("  Hybrid: Real-time at edge, batch at cloud");
        }
    };

    public abstract void deploy();
}

// ============== Main Class ==============
public class IoTMultiNodeSystem {

    public static void demonstrateLevel4() {
        System.out.println("\n========== LEVEL 4: Multiple Nodes + Central ==========");
        CentralHub hub = new CentralHub();

        // Home automation: multiple sensors -> central hub
        hub.registerNode(new IoTNode("temp-1", "living-room"));
        hub.registerNode(new IoTNode("temp-2", "bedroom"));
        hub.registerNode(new IoTNode("motion-1", "entrance"));
        hub.registerNode(new IoTNode("light-1", "kitchen"));

        List<SensorReading> data = hub.collectFromAllNodes();
        System.out.println("\nAggregated readings:");
        data.forEach(r -> System.out.println("  " + r));

        Map<String, Double> stats = hub.aggregateData(data);
        System.out.println("\nHub Statistics: " + stats);
        System.out.println("Local storage: " + hub.getLocalStorageSize() + " records");
    }

    public static void demonstrateLevel5() {
        System.out.println("\n========== LEVEL 5: Multiple Nodes + Cloud ==========");
        CentralHub hub = new CentralHub();
        CloudPlatform cloud = new CloudPlatform();

        // Environmental monitoring: sensors -> cloud
        for (int i = 1; i <= 5; i++) {
            hub.registerNode(new IoTNode("env-sensor-" + i, "park-" + i));
        }

        List<SensorReading> data = hub.collectFromAllNodes();
        cloud.store(data);
        cloud.advancedAnalytics(data);
    }

    public static void demonstrateLevel6() {
        System.out.println("\n========== LEVEL 6: Hybrid Edge + Cloud ==========");
        // Level 6 uses HYBRID deployment template
        DeploymentTemplate.HYBRID.deploy();
    }

    public static void main(String[] args) {
        System.out.println("╔════════════════════════════════════════════════════╗");
        System.out.println("║  IoT MULTI-NODE SYSTEM - Java Implementation       ║");
        System.out.println("╚════════════════════════════════════════════════════╝");

        // Demonstrate Levels 4-6
        demonstrateLevel4();
        demonstrateLevel5();
        demonstrateLevel6();

        // Demonstrate all deployment templates
        System.out.println("\n╔════════════════════════════════════════════════════╗");
        System.out.println("║  DEPLOYMENT TEMPLATES                            ║");
        System.out.println("╚════════════════════════════════════════════════════╝");

        for (DeploymentTemplate template : DeploymentTemplate.values()) {
            template.deploy();
        }

        System.out.println("\n=======================================================");
        System.out.println("System demonstration complete!");
    }
}
